func (f *CommandFactory) newDocDependentsCommand() *cobra.Command {
	return &cobra.Command{
		Use:   "dependents <id>",
		Short: "Show what depends on a document",
		Args:  cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			graph, err := f.buildDocGraph()
			if err != nil {
				return err
			}
			dependents, err := graph.DependentIDs(args[0])
			if err != nil {
				return err
			}
			if len(dependents) == 0 {
				fmt.Fprintln(cmd.OutOrStdout(), "No dependents.")
				return nil
			}
			for _, id := range dependents {
				doc := graph.Documents[id]
				if doc != nil {
					fmt.Fprintf(cmd.OutOrStdout(), "%s  %s\n", id, doc.Path)
				} else {
					fmt.Fprintln(cmd.OutOrStdout(), id)
				}
			}
			return nil
		},
	}
}

func (f *CommandFactory) newDocValidateCommand() *cobra.Command {
	return &cobra.Command{
		Use:   "validate",
		Short: "Validate document graph (check for cycles, missing deps)",
		Args:  cobra.NoArgs,
		RunE: func(cmd *cobra.Command, args []string) error {
			graph, err := f.buildDocGraph()
			if err != nil {
				return err
			}
			out := cmd.OutOrStdout()
			hasDiagnostics := false
			hasFatalIssue := false
			for _, issue := range graph.Issues {
				hasDiagnostics = true
				if isDocValidateFatalIssue(issue.Kind) {
					hasFatalIssue = true
					fmt.Fprintf(out, "error: %s\n", issue.Message)
					continue
				}
				fmt.Fprintf(out, "warning: %s\n", issue.Message)
			}
			for _, warning := range graph.ValidationWarnings {
				hasDiagnostics = true
				fmt.Fprintf(out, "warning: %s\n", warning)
			}
			if !hasDiagnostics {
				fmt.Fprintln(cmd.OutOrStdout(), "Document graph is valid.")
				return nil
			}
			if hasFatalIssue {
				cmd.SilenceUsage = true
				cmd.SilenceErrors = true
				return NewExitError(ExitCodeGeneralError, "")
			}
			return nil
		},
	}
}

func isDocValidateFatalIssue(kind docgraph.IssueKind) bool {
	return kind == docgraph.IssueMissingMetricArtifact
}

