	} `yaml:"examples"`
	IDFormat struct {
		Prefix      string `yaml:"prefix"`
		Pattern     string `yaml:"pattern"`
		Example     string `yaml:"example"`
		Description string `yaml:"description"`
	} `yaml:"id_format"`
	Name   string `yaml:"name"`
	ID     string `yaml:"id"`
	Prefix string `yaml:"prefix"`
