 46	func (f *CommandFactory) runDocProse(cmd *cobra.Command, args []string) error {
 47		changed, _ := cmd.Flags().GetBool("changed")
 48	
 49		cfg, err := config.LoadWithWorkingDir(f.docRoot())
 50		if err != nil {
 51			return err
 52		}
 53	
 54		settings, err := resolveProseSettings(cfg)
 55		if err != nil {
 56			return err
 57		}
 58	
 59		if err := maybeReportMissingRunner(cmd, settings.Runner); err != nil {
 60			return err
 61		}
 62	
 63		rootDir := f.docRoot()
 64		var relPaths []string
 65		if changed {
 66			if len(args) > 0 {
 67				return fmt.Errorf("use either --changed or explicit paths, not both")
 68			}
 69			relPaths, err = changedMarkdownPaths(rootDir)
 70			if err != nil {
 71				return err
 72			}
 73		} else {
 74			if len(args) == 0 {
 75				return fmt.Errorf("provide one or more paths or pass --changed")
 76			}
 77			relPaths = append([]string(nil), args...)
 78		}
 79	
 80		checker, err := docprose.NewChecker(settings.Mode, settings.Vocabulary)
 81		if err != nil {
 82			return err
 83		}
 84	
 85		var findings []docprose.Finding
 86		for _, relPath := range relPaths {
 87			cleanRel, absPath, ok := normalizeDocPath(rootDir, relPath)
 88			if !ok {
 89				continue
 90			}
 91			if !strings.EqualFold(filepath.Ext(cleanRel), ".md") {
 92				continue
 93			}
 94			if !pathAllowed(cleanRel, settings.Includes, settings.Excludes) {
 95				continue
 96			}
 97			content, readErr := os.ReadFile(absPath)
 98			if readErr != nil {
 99				if os.IsNotExist(readErr) {
100					continue
101				}
102				return fmt.Errorf("read %s: %w", relPath, readErr)
103			}
104			for _, finding := range checker.Findings(cleanRel, string(content)) {
105				if settings.Severity != "" {
106					finding.Severity = settings.Severity
107				}
108				findings = append(findings, finding)
109			}
110		}
111	
112		sort.Slice(findings, func(i, j int) bool {
113			if findings[i].File != findings[j].File {
114				return findings[i].File < findings[j].File
115			}
116			if findings[i].Line != findings[j].Line {
117				return findings[i].Line < findings[j].Line
118			}
119			return findings[i].RuleID < findings[j].RuleID
120		})
121	
122		out := cmd.OutOrStdout()
123		if len(findings) == 0 {
124			if changed {
125				fmt.Fprintln(out, "No changed Markdown prose findings.")
126			} else {
127				fmt.Fprintln(out, "No prose findings.")
128			}
129			return nil
130		}
131	
132		for _, finding := range findings {
133			fmt.Fprintf(out, "%s:%d [%s] %s\n", finding.File, finding.Line, finding.Severity, finding.RuleID)
134			fmt.Fprintf(out, "  rationale: %s\n", finding.Rationale)
135			fmt.Fprintf(out, "  suggested edit: %s\n", finding.SuggestedEdit)
136		}
137	
138		if isBlockingProsePolicy(settings.Policy, settings.Severity) {
139			cmd.SilenceUsage = true
140			cmd.SilenceErrors = true
141			return NewExitError(ExitCodeGeneralError, "")
142		}
143		return nil
144	}
