217		}
218	
219		var paths []string
220		for _, line := range strings.Split(strings.TrimSpace(string(out)), "\n") {
221			if line == "" || len(line) < 3 {
222				continue
223			}
224			status := line[:2]
225			pathText := strings.TrimSpace(line[3:])
226			if pathText == "" {
227				continue
228			}
229			if strings.Contains(pathText, " -> ") {
230				parts := strings.Split(pathText, " -> ")
231				pathText = parts[len(parts)-1]
232			}
233			if strings.ContainsRune(status, 'D') {
234				continue
235			}
236			if !strings.EqualFold(filepath.Ext(pathText), ".md") {
237				continue
238			}
239			paths = append(paths, filepath.ToSlash(pathText))
240		}
241		sort.Strings(paths)
242		return paths, nil
243	}
