245	func normalizeDocPath(rootDir, input string) (string, string, bool) {
246		if strings.TrimSpace(input) == "" {
247			return "", "", false
248		}
249		absPath := input
250		if !filepath.IsAbs(input) {
251			absPath = filepath.Join(rootDir, input)
252		}
253		absPath = filepath.Clean(absPath)
254		relPath, err := filepath.Rel(rootDir, absPath)
255		if err != nil {
256			relPath = filepath.ToSlash(filepath.Clean(input))
257		} else {
258			relPath = filepath.ToSlash(relPath)
259		}
260		return relPath, absPath, true
